@page "/notifications"
@rendermode InteractiveServer
@using BlazorApp.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@_notifications.Count</span></h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;

    // OnInitialized runs during both prerender and interactive render.
    // Load initial data here so it appears in the server-rendered HTML.
    protected override void OnInitialized()
    {
        _notifications = NotificationService.GetAll();
    }

    // OnAfterRenderAsync with firstRender==true fires only when the component
    // is live and interactive in the browser — never during static SSR prerender.
    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);
            }
            catch (OperationCanceledException)
            {
                break;
            }

            // Simulate an external notification arriving
            NotificationService.SimulateIncoming();

            // Fetch only new notifications since our last known ID
            var lastId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
            var newOnes = NotificationService.GetSince(lastId);

            if (newOnes.Count > 0)
            {
                _notifications.AddRange(newOnes);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

